	imgs =  f"<a style=\\\"font:\\\" target=\\\"_blank\\\" href=\\\"{'fig/%s.html' % question }\\\">Click to open animation</a><hr>" + \
	        "".join(("<img  src=\\\"%s\\\" \><hr>" % img) for img in url_to_imgs[url])

