	template = open("index.html").read()
	with open(fig_path + question + ".html", "w") as w:

		imgs = "".join(("<img style='display:none;max-width: 100%%' src='%s' onclick='nextImage()'/>" % img) for img in url_to_imgs[url])
		w.write(template.replace("<insert></insert>", imgs))



